{"code": "import json
import os

# Load NYSE non-ETF stock data
stockinfo_path = locals().get('var_functions.query_db:0')
if isinstance(stockinfo_path, str) and stockinfo_path.endswith('.json'):
    with open(stockinfo_path, 'r') as f:
        stockinfo_data = json.load(f)
else:
    stockinfo_data = locals().get('var_functions.query_db:0', [])

# Create symbol to name mapping
symbol_to_name = {stock['Symbol']: stock['Company Description'] for stock in stockinfo_data}
nyse_symbols = list(symbol_to_name.keys())

# Generate analysis queries for all stocks - we'll do this in batches
all_queries = []
for symbol in nyse_symbols:
    query = {
        'stock': symbol,
        'sql': f'SELECT "{symbol}" as symbol, COUNT(*) as total_days, SUM(CASE WHEN Close > Open THEN 1 ELSE 0 END) as up_days, SUM(CASE WHEN Close < Open THEN 1 ELSE 0 END) as down_days FROM \"{symbol}\" WHERE Date >= \'2017-01-01\' AND Date <= \'2017-12-31\''
    }
    all_queries.append(query)

print('__RESULT__:')
print(json.dumps({
    'query_count': len(all_queries),
    'sample_queries': all_queries[:3]
}))"}

